import { BrowserRouter, Routes, Route } from "react-router-dom";
import Verify from "./Verify";
import Verified from "./Verified";

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Verify />} />
        <Route path="/verified" element={<Verified />} />
      </Routes>
    </BrowserRouter>
  );
}
